sql:
SELECT SUM(awards.value) AS total_award_value
FROM awards
INNER JOIN delegate_award_history ON awards.award_id = delegate_award_history.award_id;

SELECT first_name, last_name, email
FROM delegates
WHERE status = 'active';

external_knowledge:
Active participants: delegates whose status is marked as 'active' (external knowledge needed to define 'active' status); 
Recognition: in the context of the query, refers to having an award (award_id is not NULL); 
Fields of study: refer to the specific curriculum areas in which the delegates are involved (external knowledge required to understand curriculum categories);
Type of award: refers to the category of the award, such as academic, participation, or leadership (external knowledge needed for the context of award categories).

sql:
SELECT delegate_id, first_name, last_name
FROM delegates
WHERE delegate_id NOT IN (
  SELECT delegate_id
  FROM delegate_award_history
);

SELECT COUNT(*) AS Active_Delegates
FROM delegates
WHERE status = 'active';

SELECT curriculum_area 
FROM curriculums
WHERE duration > 6;

SELECT instructor_id, first_name, last_name
FROM instructors
WHERE instructor_id NOT IN (SELECT instructor_id FROM curriculums);

external_knowledge:
Average Population: The arithmetic mean of the population of all counties;
Total Area: The sum of areas of all counties in square kilometers;
Awarded Delegates: Delegates who have received any form of recognition or award, indicated by the presence of a non-zero 'award_id'.;

sql:
SELECT curriculum_area 
FROM curriculums 
WHERE duration = (SELECT MAX(duration) FROM curriculums);

SELECT delegate_id, first_name, last_name, email
FROM delegates
ORDER BY first_name ASC;

SELECT AVG(population) AS Average_Population 
FROM counties 
WHERE county_id IN (SELECT county_id FROM delegates);
